		orderID := total_ship + oi
		ori := oris[oi]
		des := dess[oi]

		var candidates []candidate

		for ai := 0; ai < activeRoutes; ai++ {
			testAssign := dispatch.Assigns[ai]
			oldCost := testAssign.Cost
			ok := testAssign.AddShip(orderID, ori, des)
			if ok {
				testAssign.GenRoute()
				if testAssign.Cost >= 0 {
					delta := testAssign.Cost - oldCost
					if delta < 1e9 {
						candidates = append(candidates, candidate{idx: ai, deltaCost: delta, isNew: false})
					}
				}
				testAssign.RemoveShip(orderID)
				testAssign.GenRoute()
			}
		}

		newSlot := -1
		for i := 0; i < MAXASSIGNS; i++ {
			if i >= activeRoutes && !usedRouteIndices[i] {
				newSlot = i
				break
			}
		}
		if newSlot >= 0 {
			var fresh Assign
			ok := fresh.AddShip(orderID, ori, des)
			if ok {
				fresh.GenRoute()
				if fresh.Cost >= 0 {
					baseDist := cal_dis(ori, des)
					regretFactor := 0.5
					composite := fresh.Cost*regretFactor + baseDist*0.3
					candidates = append(candidates, candidate{idx: newSlot, deltaCost: composite, isNew: true})
				}
			}
		}

		if len(candidates) > 0 {
			bestIdx := 0
			bestVal := candidates[0].deltaCost
