Greedy insertion with time-window feasibility check, fallback to new assign if all existing assigns fail, and randomized candidate evaluation.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	assignOrder := make([]int, dispatch.AssignsLen+len(oris))
	for i := range assignOrder {
		assignOrder[i] = i
	}
	rand.Shuffle(len(assignOrder), func(i, j int) {
		assignOrder[i], assignOrder[j] = assignOrder[j], assignOrder[i]
	})
	insertedCount := 0
	for _, idx := range orderIndices {
		ori := oris[idx]
		des := dess[idx]
		shipID := total_ship + idx
		inserted := false
		bestCostDelta := math.MaxFloat64
		bestAssignIdx := -1
		tempAssignsCopy := make([]Assign, len(assignOrder))
		for k, ai := range assignOrder {
			if ai < MAXASSIGNS {
				tempAssignsCopy[k] = dispatch.Assigns[ai]
			}
		}
		for _, ai := range assignOrder {
			if ai >= MAXASSIGNS {
				continue
			}
			candidate := &tempAssignsCopy[ai]
			prevCost := candidate.Cost
			success := candidate.AddShip(shipID, ori, des)
			if success {
				candidate.GenRoute()
				if candidate.Cost >= 0 {
					costDelta := candidate.Cost - prevCost
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = ai
					}
				}
				candidate.RemoveShip(shipID)
				candidate.GenRoute()
			}
		}
		if bestAssignIdx >= 0 {
			finalSuccess := dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			if finalSuccess {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				if dispatch.Assigns[bestAssignIdx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[bestAssignIdx].RemoveShip(shipID)
					dispatch.Assigns[bestAssignIdx].GenRoute()
				}
			}
		}
		if !inserted {
			newAssignIdx := dispatch.AssignsLen
			if newAssignIdx < MAXASSIGNS {
				dispatch.Assigns[newAssignIdx] = Assign{}
				success := dispatch.Assigns[newAssignIdx].AddShip(shipID, ori, des)
				if success {
					dispatch.Assigns[newAssignIdx].GenRoute()
					if dispatch.Assigns[newAssignIdx].Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						dispatch.Assigns[newAssignIdx].RemoveShip(shipID)
					}
				}
			}
		}
		if !inserted {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx] = Assign{}
				ok := dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						dispatch.Assigns[fallbackIdx].RemoveShip(shipID)
					}
				}
			}
		}
		insertedCount++
	}
