			}
			dispatch.Assigns[ai].RemoveShip(id)
			dispatch.Assigns[ai].GenRoute()
		}
		if len(bestCands) == 0 {
			if safeSeedIdx < MAXASSIGNS && safeSeedIdx <= dispatch.AssignsLen {
				addOk := false
				if safeSeedIdx == dispatch.AssignsLen {
					tempAsgn := &dispatch.Assigns[safeSeedIdx]
					tempAsgn.AddShip(id, oris[oi], dess[oi])
					tempAsgn.GenRoute()
					if tempAsgn.Cost >= 0 {
						dispatch.AssignsLen++
						addOk = true
					} else {
						tempAsgn.RemoveShip(id)
						tempAsgn.GenRoute()
					}
				} else if safeSeedIdx < dispatch.AssignsLen {
					addOk = dispatch.Assigns[safeSeedIdx].AddShip(id, oris[oi], dess[oi])
					if addOk {
						dispatch.Assigns[safeSeedIdx].GenRoute()
						if dispatch.Assigns[safeSeedIdx].Cost < 0 {
							dispatch.Assigns[safeSeedIdx].RemoveShip(id)
							dispatch.Assigns[safeSeedIdx].GenRoute()
							addOk = false
						}
					}
				}
				if !addOk {
					for fi := 0; fi < MAXASSIGNS; fi++ {
						asgn := &dispatch.Assigns[fi]
						if asgn.AddShip(id, oris[oi], dess[oi]) {
							asgn.GenRoute()
							if asgn.Cost >= 0 {
								if fi >= dispatch.AssignsLen {
									dispatch.AssignsLen = fi + 1
								}
								break
							}
							asgn.RemoveShip(id)
							asgn.GenRoute()
						}
					}
				}
			}
			continue
		}
		sort.Slice(bestCands, func(i, j int) bool {
			return bestCands[i].costInc < bestCands[j].costInc
		})
		regretK := 2
		if len(bestCands) < regretK {
			regretK = len(bestCands)
		}
		selectedIdx := bestCands[0].idx
		if regretK > 1 {
			regretScore := bestCands[1].costInc - bestCands[0].costInc
			if regretScore > 0 && regretScore*0.7+bestCands[0].costInc > bestCands[regretK-1].costInc {
				selectedIdx = bestCands[regretK-1].idx
			}
		}
		ok := dispatch.Assigns[selectedIdx].AddShip(id, oris[oi], dess[oi])
		if ok {
			dispatch.Assigns[selectedIdx].GenRoute()
			if dispatch.Assigns[selectedIdx].Cost < 0 {
				dispatch.Assigns[selectedIdx].RemoveShip(id)
				dispatch.Assigns[selectedIdx].GenRoute()
				fallbackDone := false
				for fi := 0; fi < MAXASSIGNS; fi++ {
					if dispatch.Assigns[fi].AddShip(id, oris[oi], dess[oi]) {
						dispatch.Assigns[fi].GenRoute()
						if dispatch.Assigns[fi].Cost >= 0 {
							if fi >= dispatch.AssignsLen {
								dispatch.AssignsLen = fi + 1
							}
							fallbackDone = true
							break
						}
						dispatch.Assigns[fi].RemoveShip(id)
						dispatch.Assigns[fi].GenRoute()
					}
				}
				if !fallbackDone && safeSeedIdx < MAXASSIGNS {
					asgn := &dispatch.Assigns[safeSeedIdx]
					if asgn.AddShip(id, oris[oi], dess[oi]) {
						asgn.GenRoute()
						if asgn.Cost >= 0 {
							if safeSeedIdx >= dispatch.AssignsLen {
								dispatch.AssignsLen = safeSeedIdx + 1
							}
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

