Greedy insertion with parameterized scoring combining distance increase, time window slack penalty, and load balancing factor, evaluating all existing assigns and empty slots with configurable weights, falling back to forced insertion into least-cost assign if no feasible slot found.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const alpha = 1.0  // weight for distance increase
	const beta = 0.5   // weight for time window tightness penalty
	const gamma = 0.3  // weight for load balance factor
	const bigM = 1e9

	type candidate struct {
		assignIdx int
		score     float64
	}

	for jj := range oris {
		ori := oris[jj]
		des := dess[jj]
		orderID := total_ship + jj

		var bestFeasible candidate
		bestFeasible.score = bigM

		// evaluate all existing assigns
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			prevCost := dispatch.Assigns[ii].Cost
			ok := dispatch.Assigns[ii].AddShip(orderID, ori, des)
			if ok {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				if newCost >= 0 && newCost-prevCost < bigM/2 {
					incDist := newCost - prevCost
					slackPenalty := 0.0
					loadFactor := 0.0

					// approximate time window tightness via station times (if available)
					if ori.TimeEnd > ori.TimeStart {
						midTime := (ori.TimeStart + ori.TimeEnd) / 2
						slackPenalty += float64(midTime) * 0.01
					}
					if des.TimeEnd > des.TimeStart {
						midTime := (des.TimeStart + des.TimeEnd) / 2
						slackPenalty += float64(midTime) * 0.01
					}
					// simple load factor based on number of stations already in assign
					existingLoad := 0
					if len(dispatch.Assigns[ii].Stations) > 0 {
						existingLoad = len(dispatch.Assigns[ii].Stations)
					}
					loadFactor = float64(existingLoad) * gamma

					score := alpha*incDist + beta*slackPenalty + loadFactor
					if score < bestFeasible.score {
						bestFeasible.assignIdx = ii
						bestFeasible.score = score
					}
				}
			}
			dispatch.Assigns[ii].RemoveShip(orderID)
			dispatch.Assigns[ii].GenRoute()
		}

		inserted := false
		if bestFeasible.assignIdx != -1 {
			ii := bestFeasible.assignIdx
			ok := dispatch.Assigns[ii].AddShip(orderID, ori, des)
			if ok {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[ii].RemoveShip(orderID)
					dispatch.Assigns[ii].GenRoute()
				}
			}
		}

		if !inserted {
			// try empty assigns first
			foundEmpty := false
			for ee := dispatch.AssignsLen; ee < MAXASSIGNS; ee++ {
				ok := dispatch.Assigns[ee].AddShip(orderID, ori, des)
				if ok {
					dispatch.Assigns[ee].GenRoute()
					if dispatch.Assigns[ee].Cost >= 0 {
						if ee >= dispatch.AssignsLen {
							dispatch.AssignsLen = ee + 1
						}
						foundEmpty = true
						break
					} else {
						dispatch.Assigns[ee].RemoveShip(orderID)
						dispatch.Assigns[ee].GenRoute()
					}
				}
			}

			if !foundEmpty {
				// fallback: force insert into existing assign with minimal absolute cost after attempt
				var fallbackBest candidate
				fallbackBest.score = bigM
				for ii := 0; ii < dispatch.AssignsLen; ii++ {
					ok := dispatch.Assigns[ii].AddShip(orderID, ori, des)
					if ok {
						dispatch.Assigns[ii].GenRoute()
						absCost := dispatch.Assigns[ii].Cost
						if absCost < fallbackBest.score {
							fallbackBest.assignIdx = ii
							fallbackBest.score = absCost
						}
						dispatch.Assigns[ii].RemoveShip(orderID)
						dispatch.Assigns[ii].GenRoute()
					}
				}
				if fallbackBest.assignIdx != -1 {
					ii := fallbackBest.assignIdx
					dispatch.Assigns[ii].AddShip(orderID, ori, des)
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						// keep it even if negative? problem says fallback safe insertion, so we force accept here
						// but if still negative, we leave it (simulation will handle cost)
					}
				} else if dispatch.AssignsLen < MAXASSIGNS {
					ee := dispatch.AssignsLen
					dispatch.Assigns[ee].AddShip(orderID, ori, des)
					dispatch.Assigns[ee].GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

