Modified greedy regret algorithm with iterative improvement passes, evaluating both existing routes and potential new empty routes, prioritizing by weighted regret score, and performing local route optimization after each batch of insertions.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nOrders := len(oris)
	orderPending := make([]bool, nOrders)
	for i := 0; i < nOrders; i++ {
		orderPending[i] = true
	}
	type SlotScore struct {
		assignIdx int
		costDelta float64
		isNew     bool
		valid     bool
	}
	type OrderEval struct {
		best       SlotScore
		secondBest SlotScore
		regret     float64
	}
	const MAXITER = 5
	for iter := 0; iter < MAXITER; iter++ {
		anyChange := false
		allEvals := make([]OrderEval, nOrders)
		pendingCount := 0
		for oi := 0; oi < nOrders; oi++ {
			if !orderPending[oi] {
				continue
			}
			pendingCount++
			var eval OrderEval
			eval.best = SlotScore{-1, 1e100, false, false}
			eval.secondBest = SlotScore{-1, 1e100, false, false}
			bestDelta := 1e100
			secDelta := 1e100
			for ai := 0; ai < dispatch.AssignsLen; ai++ {
				oldCost := dispatch.Assigns[ai].Cost
				if !dispatch.Assigns[ai].AddShip(total_ship+oi, oris[oi], dess[oi]) {
					continue
				}
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				if newCost < 0 {
					dispatch.Assigns[ai].RemoveShip(total_ship + oi)
					dispatch.Assigns[ai].GenRoute()
					dispatch.Assigns[ai].Cost = oldCost
					continue
				}
				delta := newCost - oldCost
				if delta < bestDelta {
					secDelta = bestDelta
					eval.secondBest = eval.best
					bestDelta = delta
					eval.best = SlotScore{ai, delta, false, true}
				} else if delta < secDelta {
					secDelta = delta
