func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx       int
		costDelta float64
		feasible  bool
	}
	orders := len(oris)
	for o := 0; o < orders; o++ {
		id := total_ship + o
		ori := oris[o]
		des := dess[o]
		best := cand{-1, 0, false}
		for i := 0; i < dispatch.AssignsLen; i++ {
			okBefore := dispatch.Assigns[i].AddShip(id, ori, des)
			if okBefore {
				oldCost := dispatch.Assigns[i].Cost
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if !best.feasible || delta < best.costDelta {
						best.idx = i
						best.costDelta = delta
						best.feasible = true
					}
				}
				dispatch.Assigns[i].RemoveShip(id)
				dispatch.Assigns[i].GenRoute()
			}
		}
		inserted := false
		if best.feasible {
			ok := dispatch.Assigns[best.idx].AddShip(id, ori, des)
			if ok {
				dispatch.Assigns[best.idx].GenRoute()
				inserted = true
			}
		}
		if !inserted {
			for i := 0; i <= dispatch.AssignsLen; i++ {
				if i == MAXASSIGNS {
					break
				}
				if i == dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
				ok := dispatch.Assigns[i].AddShip(id, ori, des)
				if ok {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						inserted = true
						break
					} else {
						dispatch.Assigns[i].RemoveShip(id)
						dispatch.Assigns[i].GenRoute()
						if i == dispatch.AssignsLen-1 {
