			if cand.valid && cand.deltaCost < bestDelta {
				bestValidIdx = cand.idx
				bestDelta = cand.deltaCost
				break
			}
		}
		if bestValidIdx != -1 {
			assign := &dispatch.Assigns[bestValidIdx]
			assign.AddShip(shipID, ori, des)
			assign.GenRoute()
			for exi := 0; exi < dispatch.AssignsLen; exi++ {
				if exi == bestValidIdx {
					continue
				}
				exAssign := &dispatch.Assigns[exi]
				for sj := 0; sj < orderCount; sj++ {
					if sj == origIdx {
						continue
					}
					checkSID := total_ship + sj
					if checkSID < shipID {
						tempOri := oris[sj]
						tempDes := dess[sj]
						oldExCost := exAssign.Cost
						okAdd := exAssign.AddShip(checkSID, tempOri, tempDes)
						if okAdd {
							exAssign.GenRoute()
							newExCost := exAssign.Cost
							if newExCost >= 0 && newExCost < oldExCost*1.05 {
								oldBestCost := assign.Cost
								assign.RemoveShip(checkSID)
								assign.GenRoute()
								testOk := assign.AddShip(checkSID, tempOri, tempDes)
								if testOk {
									assign.GenRoute()
									if assign.Cost >= 0 && assign.Cost+newExCost < oldBestCost+oldExCost {
										exAssign.RemoveShip(checkSID)
										exAssign.GenRoute()
										assign.RemoveShip(checkSID)
										assign.GenRoute()
										assign.AddShip(checkSID, tempOri, tempDes)
										assign.GenRoute()
										continue
									}
									assign.RemoveShip(checkSID)
									assign.GenRoute()
								}
								assign.AddShip(checkSID, tempOri, tempDes)
								assign.GenRoute()
							}
							exAssign.RemoveShip(checkSID)
							exAssign.GenRoute()
						}
					}
				}
			}
		} else {
			inserted := false
			for fi := 0; fi <= dispatch.AssignsLen; fi++ {
				var assign *Assign
				if fi == dispatch.AssignsLen {
					if dispatch.AssignsLen < MAXASSIGNS {
						assign = &dispatch.Assigns[fi]
					} else {
						continue
					}
				} else {
					assign = &dispatch.Assigns[fi]
				}
				ok := assign.AddShip(shipID, ori, des)
				if ok {
					assign.GenRoute()
					if assign.Cost >= 0 {
						if fi == dispatch.AssignsLen {
							dispatch.AssignsLen++
						}
						inserted = true
						break
					}
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				assign := &dispatch.Assigns[dispatch.AssignsLen]
				assign.AddShip(shipID, ori, des)
				assign.GenRoute()
				if assign.Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					assign.RemoveShip(shipID)
					assign.GenRoute()
				}
			} else if !inserted && dispatch.AssignsLen == MAXASSIGNS {
				for si := 0; si < dispatch.AssignsLen; si++ {
					assign := &dispatch.Assigns[si]
					ok := assign.AddShip(shipID, ori, des)
					if ok {
						assign.GenRoute()
						if assign.Cost >= 0 {
							inserted = true
							break
						}
						assign.RemoveShip(shipID)
						assign.GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

