population.algorithm:
Use regret-based insertion: evaluate each unassigned ship against all routes via feasible insertions considering route cost change and future opportunity loss, pick the ship-order pair with highest regret difference between best and second-best insertion, then execute the best insertion; fallback to cheapest new route creation if no feasible insertion exists.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const (
		alpha = 1.0
		beta  = 0.3
		gamma = 0.7
	)
	type insertion struct {
		assignIdx int
		pos       int
		costInc   float64
		feasible  bool
	}
	unassigned := make([]int, len(oris))
	for i := range oris {
		unassigned[i] = i
	}
	for len(unassigned) > 0 {
		bestRegret := -1e9
		var bestShip int
		var bestIns insertion
		for _, idx := range unassigned {
			sid := total_ship + idx
			ori := oris[idx]
			des := dess[idx]
			var best1, best2 insertion
			best1.costInc = 1e18
			best2.costInc = 1e18
			for ai := 0; ai < dispatch.AssignsLen; ai++ {
				assignCopy := dispatch.Assigns[ai]
				if assignCopy.AddShip(sid, ori, des) {
					assignCopy.GenRoute()
					if assignCopy.Cost >= 0 {
						incr := assignCopy.Cost - dispatch.Assigns[ai].Cost
						penalty := gamma * cal_dis(assignCopy.StationCurrent, ori)
						totalIncr := incr + beta*penalty
						if totalIncr < best1.costInc {
							best2 = best1
							best1 = insertion{ai, -1, totalIncr, true}
						} else if totalIncr < best2.costInc {
							best2 = insertion{ai, -1, totalIncr, true}
						}
					}
				}
			}
			regretVal := 0.0
			selectedIns := insertion{}
			if best1.feasible && best2.feasible {
				regretVal = best2.costInc - best1.costInc
				selectedIns = best1
			} else if best1.feasible {
				regretVal = best1.costInc
				selectedIns = best1
			}
			if !best1.feasible {
				if dispatch.AssignsLen < MAXASSIGNS {
					tmpAssign := dispatch.Assigns[dispatch.AssignsLen]
					if tmpAssign.AddShip(sid, ori, des) {
						tmpAssign.GenRoute()
						if tmpAssign.Cost >= 0 {
							regretVal = 0.5 * tmpAssign.Cost
							selectedIns = insertion{dispatch.AssignsLen, -1, tmpAssign.Cost, true}
						}
					}
				}
			}
			if selectedIns.feasible && regretVal > bestRegret {
				bestRegret = regretVal
				bestShip = idx
				bestIns = selectedIns
			}
		}
		if bestRegret <= -1e8 {
			break
		}
		sid := total_ship + bestShip
		ori := oris[bestShip]
		des := dess[bestShip]
		if bestIns.assignIdx < dispatch.AssignsLen {
			dispatch.Assigns[bestIns.assignIdx].AddShip(sid, ori, des)
			dispatch.Assigns[bestIns.assignIdx].GenRoute()
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(sid, ori, des)
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
					dispatch.AssignsLen++
				}
			}
		}
		newUnassigned := make([]int, 0, len(unassigned)-1)
		for _, u := range unassigned {
			if u != bestShip {
				newUnassigned = append(newUnassigned, u)
			}
		}
		unassigned = newUnassigned
	}
	if len(unassigned) > 0 {
		for _, idx := range unassigned {
			if dispatch.AssignsLen >= MAXASSIGNS {
				continue
			}
			sid := total_ship + idx
			ori := oris[idx]
			des := dess[idx]
			origLen := dispatch.AssignsLen
			dispatch.Assigns[origLen].AddShip(sid, ori, des)
			dispatch.Assigns[origLen].GenRoute()
			if dispatch.Assigns[origLen].Cost >= 0 {
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

