				regretVal = best2.costInc - best1.costInc
				selectedIns = best1
			} else if best1.feasible {
				regretVal = best1.costInc
				selectedIns = best1
			}
			if !best1.feasible {
				if dispatch.AssignsLen < MAXASSIGNS {
					tmpAssign := dispatch.Assigns[dispatch.AssignsLen]
					if tmpAssign.AddShip(sid, ori, des) {
						tmpAssign.GenRoute()
						if tmpAssign.Cost >= 0 {
							regretVal = 0.5 * tmpAssign.Cost
							selectedIns = insertion{dispatch.AssignsLen, -1, tmpAssign.Cost, true}
						}
					}
				}
			}
			if selectedIns.feasible && regretVal > bestRegret {
				bestRegret = regretVal
				bestShip = idx
				bestIns = selectedIns
			}
		}
		if bestRegret <= -1e8 {
			break
		}
		sid := total_ship + bestShip
		ori := oris[bestShip]
		des := dess[bestShip]
		if bestIns.assignIdx < dispatch.AssignsLen {
			dispatch.Assigns[bestIns.assignIdx].AddShip(sid, ori, des)
			dispatch.Assigns[bestIns.assignIdx].GenRoute()
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(sid, ori, des)
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
					dispatch.AssignsLen++
				}
			}
		}
		newUnassigned := make([]int, 0, len(unassigned)-1)
		for _, u := range unassigned {
			if u != bestShip {
				newUnassigned = append(newUnassigned, u)
			}
		}
		unassigned = newUnassigned
	}
	if len(unassigned) > 0 {
		for _, idx := range unassigned {
			if dispatch.AssignsLen >= MAXASSIGNS {
				continue
			}
			sid := total_ship + idx
			ori := oris[idx]
			des := dess[idx]
			origLen := dispatch.AssignsLen
			dispatch.Assigns[origLen].AddShip(sid, ori, des)
			dispatch.Assigns[origLen].GenRoute()
			if dispatch.Assigns[origLen].Cost >= 0 {
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

